member.remarks:
            The following HTTP methods are supported:


HEAD

OPTIONS

TRACE

GET

PUT

POST

DELETE

            Used in conjunction with , the following code will execute a call to an endpoint and handle the response:

            // 1. Construct request
            var url = "http://cobaltservices.ci.int.thomsonreuters.com/DataRoom/v1/constraints/userdocuments";
            var request = HttpUtils.ConstructHttpWebRequest(HttpUtils.HttpMethod.Get, url, MimeType.Application.Json);

            // 2. Send request to endpoint & parse response
            using (var response = HttpUtils.GetHttpWebResponse(request))
            {
                EndpointResponse<string> endpointResponse;
                var statusCode = response.StatusCode;
                if (statusCode == HttpStatusCode.OK)
                {
                    using (var streamReader = new StreamReader(response.GetResponseStream(), Encoding.UTF8))
                    {
                        endpointResponse = new EndpointResponse<string>(streamReader.ReadToEnd(), response.Headers);
                    }
                }
                else
                {
                    var exceptionMessage = HttpUtils.HandleHttpResponseException(response, Encoding.UTF8, request.Headers);
                    throw new HttpResponseException(statusCode, exceptionMessage);
                }

                // 3. Validate
                Assert.IsTrue(endpointResponse.ResponseBody.Length > 0, "Response Body is empty.");
                Assert.IsTrue(endpointResponse.Headers.Count > 0, "No headers returned.");
            }

Example use case for a class called Car:

public override bool Equals(Object aThat)
{
    if (aThat == null || GetType() != aThat.GetType())
    {
        return false;
    }

    // cast to native object is now safe
    Car that = (Car) aThat;

    // now a proper field-by-field evaluation can be made
    return EqualsUtils.AreEqual(this.Name, that.Name) && EqualsUtils.AreEqual(this.NumDoors, that.NumDoors) && EqualsUtils.AreEqual(this.GasMileage, that.GasMileage)
            && EqualsUtils.AreEqual(this.Color, that.Color) && EqualsUtils.AreEqual(this.MaintenanceChecks, that.MaintenanceChecks);
}

Example use case:

public override int GetHashCode()
{
    int result = HashCodeUtils.Seed;

    // collect the contributions of various fields
    result = HashCodeUtils.Hash(result, this.fPrimitive);
    result = HashCodeUtils.Hash(result, this.fObject);
    result = HashCodeUtils.Hash(result, this.fArray);
    return result;
}
